/// <returns>ETGSPAINSalesPackingSlipImport</returns>
public ETGSPAINSalesPackingSlipImport parmETGSPAINSalesPackingSlipImport(ETGSPAINSalesPackingSlipImport _ETGSPAINSalesPackingSlipImport = ETGSPAINSalesPackingSlipImport)
{
    ETGSPAINSalesPackingSlipImport = _ETGSPAINSalesPackingSlipImport;

    return ETGSPAINSalesPackingSlipImport;
}

/// <summary>
/// Static main method of the class.
/// </summary>
/// <param name = "_args">Args</param>
public static void main(Args _args)
{
    ETGSPAINSalesPackingSlipImportShowError ETGSPAINSalesPackingSlipImportShowError = ETGSPAINSalesPackingSlipImportShowError::construct(_args);

    ETGSPAINSalesPackingSlipImportShowError.run();
}

/// <summary>
/// Constructor that creates an instance of the <c>ETGSPAINSalesPackingSlipImportShowError</c> class
/// based on the provided Args.
/// </summary>
/// <param name = "_args">Args</param>
/// <returns>ETGSPAINSalesPackingSlipImportShowError</returns>
public static ETGSPAINSalesPackingSlipImportShowError construct(Args _args)
{
    ETGSPAINSalesPackingSlipImportShowError ETGSPAINSalesPackingSlipImportShowError = new ETGSPAINSalesPackingSlipImportShowError();

    if (_args && _args.record() && _args.record().tableId == tableNum(ETGSPAINSalesPackingSlipImport))
    {
        ETGSPAINSalesPackingSlipImportShowError.parmETGSPAINSalesPackingSlipImport(_args.record());
    }

    return ETGSPAINSalesPackingSlipImportShowError;
}

/// <summary>
/// Main <c>run</c> method of the class.
/// </summary>
void run()
{
    Common				                record;
    #OCCRetryCount

    try
    {
        ttsBegin;

        if (ETGSPAINSalesPackingSlipImport && conLen(ETGSPAINSalesPackingSlipImport.ErrorLogContainer) > 0)
        {
            infolog.clear();
            infolog.import(ETGSPAINSalesPackingSlipImport.ErrorLogContainer, true);
        }

        ttsCommit;
    }
    catch (Exception::Deadlock)
    {
        retry;
    }
    catch (Exception::UpdateConflict)
    {
        if (appl.ttsLevel() == 0)
        {
            if (xSession::currentRetryCount() >= #RetryNum)
            {
                throw Exception::UpdateConflictNotRecovered;
            }
            else
            {
                retry;
            }
        }
        else
        {
            throw Exception::UpdateConflict;
        }
    }
}
